--
-- Table structure for table `bang_luong_thang`
--

DROP TABLE IF EXISTS `bang_luong_thang`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `bang_luong_thang` (
  `id` int NOT NULL AUTO_INCREMENT,
  `nv_ho_so_id` int NOT NULL,
  `bang_cong_thang_id` int NOT NULL,
  `thang` int NOT NULL,
  `nam` int NOT NULL,
  `tong_cong` decimal(5,2) NOT NULL DEFAULT '0.00',
  `tong_ot` decimal(5,2) NOT NULL DEFAULT '0.00',
  `luong_co_ban_tinh` decimal(18,2) NOT NULL DEFAULT '0.00',
  `phu_cap_tinh` decimal(18,2) NOT NULL DEFAULT '0.00',
  `thuong` decimal(18,2) NOT NULL DEFAULT '0.00',
  `khau_tru` decimal(18,2) NOT NULL DEFAULT '0.00',
  `tong_luong` decimal(18,2) NOT NULL DEFAULT '0.00',
  `trang_thai` varchar(30) NOT NULL,
  `is_dirty` tinyint(1) NOT NULL DEFAULT '0',
  `ngay_tinh_luong` datetime DEFAULT NULL,
  `ngay_gui_duyet` datetime DEFAULT NULL,
  `ngay_duyet_giam_doc` datetime DEFAULT NULL,
  `ngay_khoa_luong` datetime DEFAULT NULL,
  `tai_khoan_tinh_id` int DEFAULT NULL,
  `tai_khoan_gui_duyet_id` int DEFAULT NULL,
  `tai_khoan_duyet_id` int DEFAULT NULL,
  `tai_khoan_khoa_id` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `FK_BANG_LUONG_NV_HO_SO` (`nv_ho_so_id`),
  KEY `FK_BANG_LUONG_BANG_CONG` (`bang_cong_thang_id`),
  KEY `FK_BANG_LUONG_TK_TINH` (`tai_khoan_tinh_id`),
  KEY `FK_BANG_LUONG_TK_GUI_DUYET` (`tai_khoan_gui_duyet_id`),
  KEY `FK_BANG_LUONG_TK_DUYET` (`tai_khoan_duyet_id`),
  KEY `FK_BANG_LUONG_TK_KHOA` (`tai_khoan_khoa_id`),
  CONSTRAINT `FK_BANG_LUONG_BANG_CONG` FOREIGN KEY (`bang_cong_thang_id`) REFERENCES `bang_cong_thang` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `FK_BANG_LUONG_NV_HO_SO` FOREIGN KEY (`nv_ho_so_id`) REFERENCES `nv_ho_so` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `FK_BANG_LUONG_TK_DUYET` FOREIGN KEY (`tai_khoan_duyet_id`) REFERENCES `tai_khoan` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `FK_BANG_LUONG_TK_GUI_DUYET` FOREIGN KEY (`tai_khoan_gui_duyet_id`) REFERENCES `tai_khoan` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `FK_BANG_LUONG_TK_KHOA` FOREIGN KEY (`tai_khoan_khoa_id`) REFERENCES `tai_khoan` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `FK_BANG_LUONG_TK_TINH` FOREIGN KEY (`tai_khoan_tinh_id`) REFERENCES `tai_khoan` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=248 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

