DROP TABLE IF EXISTS `cham_cong`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `cham_cong` (
  `id` int NOT NULL AUTO_INCREMENT,
  `nv_ho_so_id` int NOT NULL,
  `bang_cong_thang_id` int NOT NULL,
  `ngay` date NOT NULL,
  `gio_vao` datetime DEFAULT NULL,
  `gio_ra` datetime DEFAULT NULL,
  `so_gio_ot` decimal(5,2) NOT NULL DEFAULT '0.00',
  `trang_thai` varchar(30) NOT NULL,
  `source_module` varchar(30) DEFAULT NULL,
  `is_locked_by_module` tinyint(1) NOT NULL DEFAULT '0',
  `ghi_chu` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `FK_CHAM_CONG_NV_HO_SO` (`nv_ho_so_id`),
  KEY `FK_CHAM_CONG_BANG_CONG` (`bang_cong_thang_id`),
  CONSTRAINT `FK_CHAM_CONG_BANG_CONG` FOREIGN KEY (`bang_cong_thang_id`) REFERENCES `bang_cong_thang` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `FK_CHAM_CONG_NV_HO_SO` FOREIGN KEY (`nv_ho_so_id`) REFERENCES `nv_ho_so` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=7301 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
