DROP TABLE IF EXISTS `cham_cong_chi_tiet`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `cham_cong_chi_tiet` (
  `id` int NOT NULL,
  `bang_cong_thang_id` int NOT NULL,
  `nv_ho_so_id` int NOT NULL,
  `ngay` date NOT NULL,
  `gio_vao` time DEFAULT NULL,
  `gio_ra` time DEFAULT NULL,
  `so_cong` decimal(3,1) DEFAULT '0.0',
  `trang_thai` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `ghi_chu` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `IDX_CHAM_CONG_CHI_TIET_BANG_CONG` (`bang_cong_thang_id`),
  KEY `IDX_CHAM_CONG_CHI_TIET_NV` (`nv_ho_so_id`),
  KEY `IDX_CHAM_CONG_CHI_TIET_NGAY` (`ngay` DESC),
  CONSTRAINT `cham_cong_chi_tiet_ibfk_1` FOREIGN KEY (`bang_cong_thang_id`) REFERENCES `bang_cong_thang` (`id`),
  CONSTRAINT `cham_cong_chi_tiet_ibfk_2` FOREIGN KEY (`nv_ho_so_id`) REFERENCES `nv_ho_so` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
